이제 현재 프로젝트에 Follow 관련 코드가 있는지 더 깊이 있게 찾아보겠습니다. 프로젝트가 실제 코드 없이 설정 파일만 있는 것으로 보이므로, 전형적인 팔로우 조회 쿼리 최적화에 대한 종합적인 분석과 개선안을 제공하겠습니다.

## 팔로우 목록 조회 쿼리 최적화 분석 및 개선안

### 1. 전형적인 문제점 분석

일반적인 팔로우 시스템에서 발생하는 문제점들:

**문제 1: N+1 쿼리 문제**
```
- 팔로우 목록 조회 (1 쿼리): List<Follow>
- 각 Follow의 follower 사용자 정보 조회 (N 쿼리)
- 각 사용자의 프로필 이미지, 상태 등 (N 쿼리)
```

**문제 2: 불필요한 컬럼 조회**
- 전체 Follow 엔티티의 모든 필드를 가져옴
- 필요없는 임시 데이터까지 메모리에 로드

**문제 3: 인덱스 누락**
- `follow.following_user_id` (팔로우 받는 사용자로 목록 조회)
- `follow.follower_user_id` (팔로워로 필터링)
- `follow.created_at` (최신순 정렬)
- 복합 인덱스 부재

### 2. 최적화된 솔루션

#### 2.1 Entity 정의 (Follow)

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/follow/FollowEntity.kt
@Entity
@Table(
    catalog = "maum",
    name = "follow",
    indexes = [
        Index(name = "idx_following_user_id_created_at", columnList = "following_user_id,created_at"),
        Index(name = "idx_follower_user_id_created_at", columnList = "follower_user_id,created_at"),
        Index(name = "idx_follower_following_unique", columnList = "follower_user_id,following_user_id", unique = true)
    ]
)
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    // 팔로우를 보낸 사용자
    @Column(name = "follower_user_id", nullable = false)
    val followerUserId: String,

    // 팔로우를 받은 사용자
    @Column(name = "following_user_id", nullable = false)
    val followingUserId: String,

    // 선택적: 팔로우 상태 (active, blocked, 등)
    @Column(name = "status", nullable = false, columnDefinition = "VARCHAR(20)")
    var status: String = "active",

    // 감사 필드
    @CreatedDate
    @Column(name = "created_at", columnDefinition = "datetime(3)", nullable = false, updatable = false)
    val createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    @Column(name = "updated_at", columnDefinition = "datetime(3)")
    var updatedAt: LocalDateTime = LocalDateTime.now()
)
```

#### 2.2 Repository 인터페이스

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt
interface FollowRepository : JpaRepository<FollowEntity, String>, FollowRepositoryCustom {
    // QueryDSL 커스텀 메서드는 FollowRepositoryCustom에서 구현
}

// 커스텀 QueryDSL 인터페이스
interface FollowRepositoryCustom {
    fun findFollowersByUserId(
        followingUserId: String,
        pageable: Pageable
    ): Page<FollowerDTO>

    fun findFollowingByUserId(
        followerUserId: String,
        pageable: Pageable
    ): Page<FollowingDTO>

    fun isFollowing(followerUserId: String, followingUserId: String): Boolean

    fun countFollowers(followingUserId: String): Long

    fun countFollowing(followerUserId: String): Long
}
```

#### 2.3 QueryDSL 구현 (성능 최적화)

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepositoryImpl.kt
@Repository
class FollowRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
    private val userRepository: UserRepository
) : FollowRepositoryCustom {

    // 문제: N+1 쿼리 해결 - 팔로워 목록 조회 (팔로우를 받은 사용자의 팔로워들)
    override fun findFollowersByUserId(
        followingUserId: String,
        pageable: Pageable
    ): Page<FollowerDTO> {
        // Step 1: Follow 엔티티와 필요한 사용자 정보를 한 번에 조회 (fetch join)
        val follow = QFollowEntity.followEntity
        val user = QUserEntity.userEntity

        val query = queryFactory
            .select(
                Projections.constructor(
                    FollowerDTO::class.java,
                    follow.id,
                    follow.followerUserId,
                    user.name,
                    user.profileImageUrl,
                    user.status,
                    follow.createdAt
                )
            )
            .from(follow)
            .leftJoin(user).on(follow.followerUserId.eq(user.id))
            .where(
                follow.followingUserId.eq(followingUserId)
                    .and(follow.status.eq("active"))
            )
            .orderBy(follow.createdAt.desc())

        // 페이지네이션 적용
        val offset = pageable.offset
        val pageSize = pageable.pageSize.toLong()

        val content = query
            .offset(offset)
            .limit(pageSize)
            .fetch()

        // 전체 개수 조회 (별도 쿼리, 하지만 최소화됨)
        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(
                follow.followingUserId.eq(followingUserId)
                    .and(follow.status.eq("active"))
            )
            .fetchOne() ?: 0L

        return PageImpl(content, pageable, total)
    }

    // 내가 팔로우하는 사용자들 조회
    override fun findFollowingByUserId(
        followerUserId: String,
        pageable: Pageable
    ): Page<FollowingDTO> {
        val follow = QFollowEntity.followEntity
        val user = QUserEntity.userEntity

        val query = queryFactory
            .select(
                Projections.constructor(
                    FollowingDTO::class.java,
                    follow.id,
                    follow.followingUserId,
                    user.name,
                    user.profileImageUrl,
                    user.status,
                    follow.createdAt
                )
            )
            .from(follow)
            .leftJoin(user).on(follow.followingUserId.eq(user.id))
            .where(
                follow.followerUserId.eq(followerUserId)
                    .and(follow.status.eq("active"))
            )
            .orderBy(follow.createdAt.desc())

        val offset = pageable.offset
        val pageSize = pageable.pageSize.toLong()

        val content = query
            .offset(offset)
            .limit(pageSize)
            .fetch()

        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(
                follow.followerUserId.eq(followerUserId)
                    .and(follow.status.eq("active"))
            )
            .fetchOne() ?: 0L

        return PageImpl(content, pageable, total)
    }

    // 팔로우 여부 확인 (최소한의 조회)
    override fun isFollowing(followerUserId: String, followingUserId: String): Boolean {
        val follow = QFollowEntity.followEntity

        return queryFactory
            .selectOne()
            .from(follow)
            .where(
                follow.followerUserId.eq(followerUserId)
                    .and(follow.followingUserId.eq(followingUserId))
                    .and(follow.status.eq("active"))
            )
            .fetchFirst() != null
    }

    // 팔로워 수 조회
    override fun countFollowers(followingUserId: String): Long {
        val follow = QFollowEntity.followEntity

        return queryFactory
            .select(follow.count())
            .from(follow)
            .where(
                follow.followingUserId.eq(followingUserId)
                    .and(follow.status.eq("active"))
            )
            .fetchOne() ?: 0L
    }

    // 팔로우 수 조회
    override fun countFollowing(followerUserId: String): Long {
        val follow = QFollowEntity.followEntity

        return queryFactory
            .select(follow.count())
            .from(follow)
            .where(
                follow.followerUserId.eq(followerUserId)
                    .and(follow.status.eq("active"))
            )
            .fetchOne() ?: 0L
    }
}
```

